What i actually ended up doing was this:
```
org_sanitize = eve_sqlalchemy.utils._sanitize_value
org_resolve_embedded_documents = eve.methods.common.resolve_embedded_documents


def _sanitize_value(value):
    if isinstance(value.__class__, DeclarativeMeta):
        resource = _get_resource(value)
        if config.DOMAIN[resource].get('self_link', None):
            return _get_uri(value)
    return org_sanitize(value)


def _get_uri(obj):
    resource = _get_resource(obj)
    return config.DOMAIN[resource]['url'] + '/' + str(_get_id(obj))


def resolve_embedded_documents(document, resource, embedded_fields):
    for field in sorted(embedded_fields, key=lambda a: a.count('.')):
        if config.DOMAIN[field].get('self_link', None):
            document[field] = [i.split('/')[-1] for i in document.get(field, [])]
    return org_resolve_embedded_documents(document, resource, embedded_fields)


eve_sqlalchemy.utils._sanitize_value = _sanitize_value
eve.methods.common.resolve_embedded_documents = resolve_embedded_documents
```

